type URLRequest struct {
	URL string `json:"url"`
}

type URLPreview struct {
	Title       string `json:"title"`
	Description string `json:"description"`
}

func FetchURLPreview(ctx echo.Context) error {
	var req URLRequest
	if err := ctx.Bind(&req); err != nil {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "Invalid request body"})
	}

	if req.URL == "" {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "URL is required"})
	}

	// Create HTTP client with timeout
	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	resp, err := client.Get(req.URL)
	if err != nil {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "Failed to fetch URL"})
	}
	defer resp.Body.Close()

	if resp.StatusCode != http.StatusOK {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "URL returned non-200 status"})
	}

	// Read response body
	body := make([]byte, 1024*1024) // 1MB limit
	n, err := resp.Body.Read(body)
	if err != nil && err.Error() != "EOF" {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "Failed to read response body"})
	}
	htmlContent := string(body[:n])

	// Extract title using regex
	titleRegex := regexp.MustCompile(`(?i)<title[^>]*>([^<]+)</title>`)
	titleMatches := titleRegex.FindStringSubmatch(htmlContent)
	title := ""
	if len(titleMatches) > 1 {
		title = strings.TrimSpace(titleMatches[1])
	}

	// Extract description using regex
	descRegex := regexp.MustCompile(`(?i)<meta[^>]*name=["']description["'][^>]*content=["']([^"']+)["']`)
	descMatches := descRegex.FindStringSubmatch(htmlContent)
	description := ""
	if len(descMatches) > 1 {
		description = strings.TrimSpace(descMatches[1])
	}

	preview := URLPreview{
		Title:       title,
		Description: description,
	}

	return ctx.JSON(http.StatusOK, preview)
}

func main() {
	e := echo.New()
	e.POST("/preview", FetchURLPreview)
	e.Start(":8080")
}

