					}
				}

				if (strings.EqualFold(metaName, "description") || strings.EqualFold(metaName, "og:description")) && metaContent != "" {
					description = metaContent
				}
			}
		}

		// Recursively visit children
		for c := n.FirstChild; c != nil; c = c.NextSibling {
			crawler(c)
		}
	}

	crawler(doc)

	return title, description
}

