package main

import (
	"encoding/json"
	"fmt"
	"net/http"
	"strings"
	"time"

	"github.com/labstack/echo/v4"
	"golang.org/x/net/html"
)

type URLRequest struct {
	URL string `json:"url"`
}

type URLResponse struct {
	Title       string `json:"title"`
	Description string `json:"description"`
}

func FetchURLPreview(ctx echo.Context) error {
	var req URLRequest
	if err := ctx.Bind(&req); err != nil {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "Invalid request body"})
	}

	if req.URL == "" {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "URL is required"})
	}

	// Create HTTP client with 3-second timeout
	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	resp, err := client.Get(req.URL)
	if err != nil {
		return ctx.JSON(http.StatusRequestTimeout, map[string]string{"error": "Request timeout"})
	}
	defer resp.Body.Close()

	if resp.StatusCode != http.StatusOK {
		return ctx.JSON(http.StatusBadGateway, map[string]string{"error": "Failed to fetch URL"})
	}

	contentType := resp.Header.Get("Content-Type")
	if !strings.Contains(contentType, "text/html") {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "URL must point to an HTML page"})
	}

	title, description, err := parseHTML(resp.Body)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "Failed to parse HTML"})
	}

	response := URLResponse{
		Title:       title,
		Description: description,
	}

	return ctx.JSON(http.StatusOK, response)
}

func parseHTML(body interface{}) (title, description string, err error) {
	doc, err := html.Parse(body.(interface{ Read([]byte) (int, error) }))
	if err != nil {
		return "", "", err
	}

	var parseNode func(*html.Node)
	parseNode = func(n *html.Node) {
		if n.Type == html.ElementNode {
			// Extract title
			if n.Data == "title" && n.FirstChild != nil {
				title = strings.TrimSpace(n.FirstChild.Data)
			}

			// Extract meta description
			if n.Data == "meta" {
				for _, attr := range n.Attr {
					if attr.Key == "name" && attr.Val == "description" {
						for _, metaAttr := range n.Attr {
							if metaAttr.Key == "content" {
								description = strings.TrimSpace(metaAttr.Val)
								break
							}
						}
					}
				}
			}
		}

		for c := n.FirstChild; c != nil; c = c.NextSibling {
			parseNode(c)
		}
	}

	parseNode(doc)
	return title, description, nil
}

func main() {
	e := echo.New()
	e.POST("/preview", FetchURLPreview)
	fmt.Println("Server is running on :8080")
	e.Start(":8080")
}

