type URLRequest struct {
	URL string `json:"url"`
}

type URLPreviewResponse struct {
	Title       string `json:"title"`
	Description string `json:"description"`
}

func FetchURLPreview(ctx echo.Context) error {
	var req URLRequest
	if err := ctx.Bind(&req); err != nil {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "invalid request body"})
	}

	if req.URL == "" {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "url is required"})
	}

	if _, err := url.ParseRequestURI(req.URL); err != nil {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "invalid URL"})
	}

	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	resp, err := client.Get(req.URL)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "failed to fetch URL"})
	}
	defer resp.Body.Close()

	if resp.StatusCode != http.StatusOK {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "non-200 response"})
	}

	body, err := io.ReadAll(resp.Body)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "failed to read response body"})
	}

	title, description := parseHTML(body)

	return ctx.JSON(http.StatusOK, URLPreviewResponse{
		Title:       title,
		Description: description,
	})
}

func parseHTML(htmlContent []byte) (title, description string) {
	doc, err := html.Parse(bytes.NewReader(htmlContent))
	if err != nil {
		return
	}

	var foundTitle, foundDescription bool
	var f func(*html.Node)
	f = func(n *html.Node) {
		if foundTitle && foundDescription {
			return
		}
		if n.Type == html.ElementNode {
			if !foundTitle && n.Data == "title" {
				for c := n.FirstChild; c != nil; c = c.NextSibling {
					if c.Type == html.TextNode {
						title = c.Data
						foundTitle = true
						break
					}
				}
			}
			if !foundDescription && n.Data == "meta" {
				for _, attr := range n.Attr {
					if (attr.Key == "name" || attr.Key == "property") && attr.Val == "description" {
						for _, a := range n.Attr {
							if a.Key == "content" {
								description = a.Val
								foundDescription = true
								break
							}
						}
						break
					}
				}
			}
		}
		if foundTitle && foundDescription {
			return
		}
		for c := n.FirstChild; c != nil; c = c.NextSibling {
			f(c)
		}
	}
	f(doc)

	return
}

