package main

import (
	"fmt"
	"io"
	"net/http"
	"net/url"
	"strings"
	"time"

	"github.com/labstack/echo/v4"
	"golang.org/x/net/html"
)

// URLRequest represents the JSON request body
type URLRequest struct {
	URL string `json:"url"`
}

// URLPreviewResponse represents the JSON response
type URLPreviewResponse struct {
	Title       string `json:"title"`
	Description string `json:"description"`
}

// FetchURLPreview handles POST requests to /preview
func FetchURLPreview(ctx echo.Context) error {
	var req URLRequest
	if err := ctx.Bind(&req); err != nil {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "Invalid request body"})
	}

	if req.URL == "" {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "URL is required"})
	}

	// Validate URL
	parsedURL, err := url.ParseRequestURI(req.URL)
	if err != nil || (parsedURL.Scheme != "http" && parsedURL.Scheme != "https") {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "Invalid URL format"})
	}

	// Create request with timeout
	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	httpReq, err := http.NewRequestWithContext(ctx.Request().Context(), http.MethodGet, req.URL, nil)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "Failed to create request"})
	}

	httpReq.Header.Set("User-Agent", "Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36")

	resp, err := client.Do(httpReq)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "Failed to fetch URL"})
	}
	defer resp.Body.Close()

	if resp.StatusCode != http.StatusOK {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": fmt.Sprintf("Received status code: %d", resp.StatusCode)})
	}

	// Limit body size to prevent memory issues
	limitedReader := io.LimitReader(resp.Body, 1<<20) // 1MB limit
	doc, err := html.Parse(limitedReader)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "Failed to parse HTML"})
	}

	title, description := extractTitleAndDescription(doc)

	return ctx.JSON(http.StatusOK, URLPreviewResponse{
		Title:       title,
		Description: description,
	})
}

func extractTitleAndDescription(n *html.Node) (title, description string) {
	var extract func(*html.Node)
	extract = func(node *html.Node) {
		if title != "" && description != "" {
			return
		}

		if node.Type == html.ElementNode {
			switch node.Data {
			case "title":
				if node.FirstChild != nil && node.FirstChild.Type == html.TextNode {
					title = strings.TrimSpace(node.FirstChild.Data)
				}
			case "meta":
				var name, content string
				for _, attr := range node.Attr {
					switch attr.Key {
					case "name":
						name = attr.Val
					case "content":
						content = attr.Val
					}
				}
				if name == "description" && content != "" {
					description = content
				}
			}
		}

		for child := node.FirstChild; child != nil; child = child.NextSibling {
			extract(child)
		}
	}

	extract(n)
	return
}

func main() {
	e := echo.New()
	e.POST("/preview", FetchURLPreview)
	e.Logger.Fatal(e.Start(":8080"))
}

