	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, URLPreviewResponse{Error: "Failed to parse HTML content"})
	}

	// Extract title and description
	title, description := "", ""
	extractMetadata(doc, &title, &description)

	return ctx.JSON(http.StatusOK, URLPreviewResponse{
		Title:       title,
		Description: description,
	})
}

// extractMetadata traverses the HTML node tree to find the title and meta description
func extractMetadata(n *html.Node, title, description *string) {
	if n.Type == html.ElementNode {
		// Extract <title> tag content
		if n.Data == "title" && n.FirstChild != nil {
			*title = strings.TrimSpace(n.FirstChild.Data)
		}

		// Extract <meta name="description"> or <meta property="description">
		if n.Data == "meta" {
			var name, prop, content string
			for _, attr := range n.Attr {
				switch attr.Key {
				case "name":
					name = attr.Val
				case "property":
					prop = attr.Val
				case "content":
					content = attr.Val
				}
			}

			if (name == "description" || prop == "description") && content != "" {
				*description = strings.TrimSpace(content)
			}
		}
	}

	// Recursively visit children
	for c := n.FirstChild; c != nil; c = c.NextSibling {
		extractMetadata(c, title, description)
	}
}

func main() {
	e := echo.New()
	e.POST("/preview", FetchURLPreview)

