	"net"
	"net/http"
	"net/url"
	"time"

	"github.com/labstack/echo/v4"
)

// Request body
type PreviewRequest struct {
	URL string `json:"url"`
}

// Response body
type PreviewResponse struct {
	Title       string `json:"title,omitempty"`
	Description string `json:"description,omitempty"`
}

func FetchURLPreview(ctx echo.Context) error {
	req := new(PreviewRequest)
	if err := ctx.Bind(req); err != nil {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "Invalid JSON"})
	}

	// Validate URL
	parsedURL, err := url.Parse(req.URL)
	if err != nil {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "Invalid URL format"})
	}

	if parsedURL.Scheme != "http" && parsedURL.Scheme != "https" {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "Only HTTP/HTTPS URLs are allowed"})
	}

	// Security Fix: SSRF Prevention
	// Resolve the hostname to check for private/internal IPs
	host := parsedURL.Hostname()
	ips, err := net.LookupIP(host)
	if err != nil {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "Could not resolve host"})
	}

	for _, ip := range ips {
		if ip.IsLoopback() || ip.IsPrivate() || ip.IsUnspecified() {
			return ctx.JSON(http.StatusForbidden, map[string]string{"error": "Access to private URLs is forbidden"})
		}
	}

	// Fetch the URL
	// Use the request context to handle cancellation/timeout from the client side
	httpReq, err := http.NewRequestWithContext(ctx.Request().Context(), http.MethodGet, req.URL, nil)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "Failed to create request"})
	}
	httpReq.Header.Set("User-Agent", "Mozilla/5.0 (compatible; URLPreviewBot/1.0)")

	client := &http.Client{Timeout: 3 * time.Second}
	resp, err := client.Do(httpReq)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "Failed to fetch URL"})
	}
	defer resp.Body.Close()

	if resp.StatusCode != http.StatusOK {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": fmt.Sprintf("HTTP %d", resp.StatusCode)})
	}

	// Security Fix: Resource Exhaustion Prevention
	// Limit the body read to 1MB to prevent memory exhaustion attacks
	body, err := io.ReadAll(io.LimitReader(resp.Body, 1<<20))
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "Failed to read response body"})
	}

	title, description := extractTitleAndDescription(body)

	return ctx.JSON(http.StatusOK, PreviewResponse{
		Title:       title,
		Description: description,
	})
}

// extractTitleAndDescription parses the HTML body to find the title and description.
// It uses basic string manipulation for efficiency and security (avoiding external regex complexity).
func extractTitleAndDescription(htmlContent []byte) (string, string) {
	title := ""
	description := ""

	// Convert content to lowercase for case-insensitive tag searching
	lowerContent := bytes.ToLower(htmlContent)

	// 1. Extract Title
	// Find <title>...</title>
	titleStartTag := []byte("<title>")
	titleEndTag := []byte("</title>")

	startIdx := bytes.Index(lowerContent, titleStartTag)
	if startIdx != -1 {
		startIdx += len(titleStartTag)
		endIdx := bytes.Index(lowerContent[startIdx:], titleEndTag)
		if endIdx != -1 {
			title = string(bytes.TrimSpace(htmlContent[startIdx : startIdx+endIdx]))
		}
	}

	// 2. Extract Description
	// Find <meta name="description" content="...">
	// Note: This is a simplified parser. It assumes standard double-quoted attributes.
	descMetaStart := []byte(`<meta name="description" content="`)
	descEndQuote := []byte(`"`)

	startIdx = bytes.Index(lowerContent, descMetaStart)
	if startIdx != -1 {
		startIdx += len(descMetaStart)
		endIdx := bytes.Index(lowerContent[startIdx:], descEndQuote)
		if endIdx != -1 {
			description = string(bytes.TrimSpace(htmlContent[startIdx : startIdx+endIdx]))
		}
	}

	return title, description
}

