type URLPreviewRequest struct {
	URL string `json:"url"`
}

type URLPreviewResponse struct {
	Title       string `json:"title"`
	Description string `json:"description"`
}

func FetchURLPreview(ctx echo.Context) error {
	var req URLPreviewRequest
	if err := ctx.Bind(&req); err != nil {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "Invalid request body"})
	}

	if req.URL == "" {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "URL is required"})
	}

	// Validate URL format
	if !strings.HasPrefix(req.URL, "http://") && !strings.HasPrefix(req.URL, "https://") {
		req.URL = "http://" + req.URL
	}

	// Create HTTP client with 3-second timeout
	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	resp, err := client.Get(req.URL)
	if err != nil {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "Failed to fetch URL: " + err.Error()})
	}
	defer resp.Body.Close()

	if resp.StatusCode != http.StatusOK {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "Failed to fetch URL: HTTP " + resp.Status})
	}

	// Parse HTML
	doc, err := html.Parse(resp.Body)
	if err != nil {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "Failed to parse HTML: " + err.Error()})
	}

	title := extractTitle(doc)
	description := extractDescription(doc)

	return ctx.JSON(http.StatusOK, URLPreviewResponse{
		Title:       title,
		Description: description,
	})
}

func extractTitle(n *html.Node) string {
	if n.Type == html.ElementNode && n.Data == "title" {
		if n.FirstChild != nil {
			return strings.TrimSpace(n.FirstChild.Data)
		}
	}

	for c := n.FirstChild; c != nil; c = c.NextSibling {
		if title := extractTitle(c); title != "" {
			return title
		}
	}
	return ""
}

func extractDescription(n *html.Node) string {
	if n.Type == html.ElementNode && n.Data == "meta" {
		for _, attr := range n.Attr {
			if strings.EqualFold(attr.Key, "name") && strings.EqualFold(attr.Val, "description") {
				for _, attr := range n.Attr {
					if strings.EqualFold(attr.Key, "content") {
						return strings.TrimSpace(attr.Val)
					}
				}
			}
		}
	}

	for c := n.FirstChild; c != nil; c = c.NextSibling {
		if description := extractDescription(c); description != "" {
			return description
		}
	}
	return ""
}

