package main

import (
	"context"
	"fmt"
	"io"
	"net/http"
	"strings"
	"time"

	"github.com/labstack/echo/v4"
	"golang.org/x/net/html"
)

type PreviewRequest struct {
	URL string `json:"url"`
}

type PreviewResponse struct {
	Title       string `json:"title"`
	Description string `json:"description"`
	URL         string `json:"url"`
}

func FetchURLPreview(ctx echo.Context) error {
	var req PreviewRequest
	if err := ctx.Bind(&req); err != nil {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "Invalid request body"})
	}

	if req.URL == "" {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "URL is required"})
	}

	// Create context with timeout
	ctx, cancel := context.WithTimeout(context.Background(), 3*time.Second)
	defer cancel()

	// Create HTTP request
	httpReq, err := http.NewRequestWithContext(ctx, http.MethodGet, req.URL, nil)
	if err != nil {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "Invalid URL"})
	}

	// Set user agent to avoid being blocked by some sites
	httpReq.Header.Set("User-Agent", "Mozilla/5.0 (compatible; URLPreviewBot/1.0)")

	// Execute the request
	client := &http.Client{}
	resp, err := client.Do(httpReq)
	if err != nil {
		if ctx.Err() == context.DeadlineExceeded {
			return ctx.JSON(http.StatusGatewayTimeout, map[string]string{"error": "Request timed out"})
		}
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": fmt.Sprintf("Failed to fetch URL: %v", err)})
	}
	defer resp.Body.Close()

	if resp.StatusCode != http.StatusOK {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": fmt.Sprintf("Received non-200 status code: %d", resp.StatusCode)})
	}

	// Check Content-Type to ensure it's HTML
	contentType := resp.Header.Get("Content-Type")
	if !strings.Contains(strings.ToLower(contentType), "text/html") {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "URL does not point to HTML content"})
	}

	// Limit body size to 10MB to prevent memory issues
	reader := io.LimitReader(resp.Body, 10*1024*1024)

	// Read the response body
	body, err := io.ReadAll(reader)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "Failed to read response body"})
	}

	// Parse HTML
	title, description := parseHTMLPreview(string(body))

	return ctx.JSON(http.StatusOK, PreviewResponse{
		Title:       title,
		Description: description,
		URL:         req.URL,
	})
}

func parseHTMLPreview(htmlContent string) (title, description string) {
	doc, err := html.Parse(strings.NewReader(htmlContent))
	if err != nil {
		return "", ""
	}

	var crawler func(*html.Node) (string, string)
	crawler = func(n *html.Node) (t, d string) {
		if n.Type == html.ElementNode {
			// Check for title - prefer og:title if available
			if t == "" && n.Data == "title" && n.FirstChild != nil {
				t = strings.TrimSpace(n.FirstChild.Data)
			}

			// Check for meta tags
			if n.Data == "meta" {
				isDescription := false
				isTitle := false
				var content string

				for _, attr := range n.Attr {
					if attr.Key == "name" || attr.Key == "property" {
						if attr.Val == "description" || attr.Val == "og:description" {
							isDescription = true
						}
						if attr.Val == "og:title" {
							isTitle = true
						}
					}
					if attr.Key == "content" {
						content = attr.Val
					}
				}

				if isDescription && content != "" {
					d = strings.TrimSpace(content)
				}
				if isTitle && content != "" {
					t = strings.TrimSpace(content)
				}
			}
		}

		// If both found, return early
		if t != "" && d != "" {
			return t, d
		}

		for c := n.FirstChild; c != nil; c = c.NextSibling {
			ct, cd := crawler(c)
			if ct != "" && (t == "" || strings.HasPrefix(ct, "og:")) {
				t = ct
			}
			if cd != "" && d == "" {
				d = cd
			}
			if t != "" && d != "" {
				return t, d
			}
		}

		return t, d
	}

	title, description = crawler(doc)
	return title, description
}

func main() {
	e := echo.New()

	// Register the handler under /preview path
	e.POST("/preview", FetchURLPreview)

	// Start the server
	if err := e.Start(":8080"); err != nil {
		fmt.Printf("Server error: %v\n", err)
	}
}

