				description = content
				return
			}
		}

		for c := n.FirstChild; c != nil; c = c.NextSibling {
			extractDescription(c)
			if description != "" {
				return
			}
		}
	}

	extractTitle(doc)
	extractDescription(doc)

	return title, description
}

