import (
	"encoding/json"
	"fmt"
	"net/http"
	"strings"
	"time"

	"github.com/labstack/echo/v4"
	"golang.org/x/net/html"
)

type previewRequest struct {
	URL string `json:"url"`
}

type previewResponse struct {
	Title       string `json:"title"`
	Description string `json:"description"`
	OriginalURL string `json:"url"`
}

// FetchURLPreview handles POST requests to extract title and meta description from a URL.
func FetchURLPreview(ctx echo.Context) error {
	var req previewRequest
	if err := ctx.Bind(&req); err != nil {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "invalid JSON payload"})
	}

	if req.URL == "" {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "url field is required"})
	}

	// Ensure the URL has a protocol, defaulting to https if missing
	if !strings.HasPrefix(req.URL, "http://") && !strings.HasPrefix(req.URL, "https://") {
		req.URL = "https://" + req.URL
	}

	// Set timeout to 3 seconds as requested
	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	resp, err := client.Get(req.URL)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "failed to fetch url: " + err.Error()})
	}
	defer resp.Body.Close()

	if resp.StatusCode != http.StatusOK {
		return ctx.JSON(http.StatusBadGateway, map[string]string{"error": fmt.Sprintf("received status code %d", resp.StatusCode)})
	}

	// Parse the HTML content
	doc, err := html.Parse(resp.Body)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "failed to parse HTML"})
	}

	title, description := parseHTML(doc)

	return ctx.JSON(http.StatusOK, previewResponse{
		Title:       title,
		Description: description,
		OriginalURL: req.URL,
	})
}

// parseHTML recursively traverses the HTML node tree to find the <title> 
// and <meta name="description"> content.
func parseHTML(n *html.Node) (title, description string) {
	var crawler func(*html.Node)
	crawler = func(node *html.Node) {
		// Optimization: Stop if we have found everything
		if title != "" && description != "" {
			return
		}

		if node.Type == html.ElementNode {
			// Extract <title> content
			if node.Data == "title" && title == "" && node.FirstChild != nil {
				title = strings.TrimSpace(node.FirstChild.Data)
			}

			// Extract <meta name="description" content="...">
			if node.Data == "meta" {
				var metaName, metaContent string
				for _, attr := range node.Attr {
					if attr.Key == "name" {
						metaName = strings.ToLower(attr.Val)
					}
					if attr.Key == "content" {
						metaContent = attr.Val
					}
				}
				if metaName == "description" && description == "" {
					description = metaContent
				}
			}
		}

		for child := node.FirstChild; child != nil; child = child.NextSibling {
			crawler(child)
		}
	}

	crawler(n)
	return
}

func main() {
	e := echo.New()
	e.POST("/preview", FetchURLPreview)

	// Start server on port 8080
	e.Logger.Fatal(e.Start(":8080"))
}

