import (
	"encoding/json"
	"fmt"
	"net/http"
	"strings"
	"time"

	"github.com/labstack/echo/v4"
	"golang.org/x/net/html"
)

// Request represents the JSON body structure for the POST request
type Request struct {
	URL string `json:"url"`
}

// Response represents the JSON structure for the preview result
type Response struct {
	Title       string `json:"title"`
	Description string `json:"description"`
	URL         string `json:"url"`
	Error       string `json:"error,omitempty"`
}

// FetchURLPreview handles POST requests to fetch and parse URL preview information
func FetchURLPreview(ctx echo.Context) error {
	var req Request

	// Bind JSON request body
	if err := ctx.Bind(&req); err != nil {
		return ctx.JSON(http.StatusBadRequest, Response{Error: "Invalid JSON body"})
	}

	// Validate URL field
	if req.URL == "" {
		return ctx.JSON(http.StatusBadRequest, Response{Error: "URL field is required"})
	}

	// Ensure URL has protocol prefix
	if !strings.HasPrefix(req.URL, "http://") && !strings.HasPrefix(req.URL, "https://") {
		req.URL = "https://" + req.URL
	}

	// Create HTTP client with 3-second timeout
	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	// Fetch the URL content
	resp, err := client.Get(req.URL)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, Response{
			Error: fmt.Sprintf("Failed to fetch URL: %v", err),
			URL:   req.URL,
		})
	}
	defer resp.Body.Close()

	// Check response status
	if resp.StatusCode != http.StatusOK {
		return ctx.JSON(http.StatusInternalServerError, Response{
			Error: fmt.Sprintf("Received status code %d", resp.StatusCode),
			URL:   req.URL,
		})
	}

	// Parse HTML content
	doc, err := html.Parse(resp.Body)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, Response{
			Error: fmt.Sprintf("Failed to parse HTML: %v", err),
			URL:   req.URL,
		})
	}

	// Extract title and description
	title := extractTitle(doc)
	description := extractMetaDescription(doc)

	return ctx.JSON(http.StatusOK, Response{
		Title:       title,
		Description: description,
		URL:         req.URL,
	})
}

// extractTitle recursively searches for the <title> tag in the HTML document
func extractTitle(n *html.Node) string {
	if n.Type == html.ElementNode && n.Data == "title" && n.FirstChild != nil {
		return strings.TrimSpace(n.FirstChild.Data)
	}

	for c := n.FirstChild; c != nil; c = c.NextSibling {
		if result := extractTitle(c); result != "" {
			return result
		}
	}

	return ""
}

// extractMetaDescription recursively searches for meta description tag
func extractMetaDescription(n *html.Node) string {
	if n.Type == html.ElementNode && n.Data == "meta" {
		var name, content string

		for _, attr := range n.Attr {
			switch attr.Key {
			case "name":
				name = attr.Val
			case "content":
				content = attr.Val
			}
		}

		if name == "description" && content != "" {
			return strings.TrimSpace(content)
		}
	}

	for c := n.FirstChild; c != nil; c = c.NextSibling {
		if result := extractMetaDescription(c); result != "" {
			return result
		}
	}

	return ""
}

func main() {
	// Create Echo instance
	e := echo.New()

	// Register the handler under /preview path
	e.POST("/preview", FetchURLPreview)

	// Start the server
	e.Logger.Fatal(e.Start(":8080"))
}

