	"github.com/labstack/echo/v4"
	"golang.org/x/net/html"
)

// UrlRequest represents the input JSON structure.
type UrlRequest struct {
	Url string `json:"url"`
}

// UrlPreview represents the output JSON structure.
type UrlPreview struct {
	Title       string `json:"title"`
	Description string `json:"description"`
}

// FetchURLPreview is the handler function that processes POST requests to /preview.
// It fetches the URL content, parses the HTML, and returns the title and description.
func FetchURLPreview(ctx echo.Context) error {
	var req UrlRequest
	if err := ctx.Bind(&req); err != nil {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "invalid JSON payload"})
	}

	if req.Url == "" {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "url field is required"})
	}

	// Ensure URL has a scheme, adding http:// if missing
	if !strings.HasPrefix(req.Url, "http://") && !strings.HasPrefix(req.Url, "https://") {
		req.Url = "http://" + req.Url
	}

	// Create a client with a 3-second timeout as requested
	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	resp, err := client.Get(req.Url)
	if err != nil {
		return ctx.JSON(http.StatusGatewayTimeout, map[string]string{"error": "request timed out"})
	}
	defer resp.Body.Close()

	if resp.StatusCode != http.StatusOK {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "failed to retrieve URL"})
	}

	// Only attempt to parse if the content is HTML
	contentType := resp.Header.Get("Content-Type")
	if !strings.Contains(contentType, "text/html") {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "content type is not HTML"})
	}

	title, description, err := parseHTML(resp.Body)
	if err != nil {
		// We proceed with empty values on parse error to maintain availability
		// Alternatively, you could return a 500 error here.
	}

	return ctx.JSON(http.StatusOK, UrlPreview{
		Title:       title,
		Description: description,
	})
}

// parseHTML extracts the page title and meta description from the HTML stream.
func parseHTML(r io.Reader) (title, description string, err error) {
	tokenizer := html.NewTokenizer(r)
	foundTitle := false
	foundDesc := false

	for {
		tt := tokenizer.Next()
		if tt == html.ErrorToken {
			// End of parsing
			break
		}

		if tt == html.StartTagToken {
			token := tokenizer.Token()

			// Look for the <title> tag
			if !foundTitle && token.Data == "title" {
				// The next token is expected to be the text content of the title
				if nextTT := tokenizer.Next(); nextTT == html.TextToken {
					title = strings.TrimSpace(tokenizer.Token().Data)
					foundTitle = true
				}
			}

			// Look for <meta name="description" ...>
			if !foundDesc && token.Data == "meta" {
				metaName := ""
				metaContent := ""
				for _, attr := range token.Attr {
					if attr.Key == "name" && strings.ToLower(attr.Val) == "description" {
						metaName = "description"
					}
					if attr.Key == "content" {
						metaContent = attr.Val
					}
				}
				if metaName == "description" {
					description = metaContent
					foundDesc = true
				}
			}
		}

		// Optimization: Stop early if we found both elements
		if foundTitle && foundDesc {
			break
		}
	}

	return title, description, nil
}

func main() {
	e := echo.New()
	e.POST("/preview", FetchURLPreview)

	// Start server on port 8080
	e.Logger.Fatal(e.Start(":8080"))
}

