// FetchURLPreview handles POST requests to extract URL preview information
func FetchURLPreview(ctx echo.Context) error {
	// Parse request body
	var reqBody struct {
		URL string `json:"url"`
	}
	if err := ctx.Bind(&reqBody); err != nil {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "Invalid request body"})
	}

	if reqBody.URL == "" {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "URL is required"})
	}

	// Create HTTP client with 3-second timeout
	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	// Fetch URL content
	resp, err := client.Get(reqBody.URL)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": err.Error()})
	}
	defer resp.Body.Close()

	// Only process HTML content
	contentType := resp.Header.Get("Content-Type")
	if !strings.Contains(contentType, "text/html") {
		return ctx.JSON(http.StatusOK, PreviewResponse{
			Title:       "",
			Description: "",
		})
	}

	// Read response body
	body, err := io.ReadAll(resp.Body)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": err.Error()})
	}

	htmlContent := string(body)

	// Extract title and description
	title := extractTitle(htmlContent)
	description := extractDescription(htmlContent)

	return ctx.JSON(http.StatusOK, PreviewResponse{
		Title:       title,
		Description: description,
	})
}

// extractTitle extracts the page title from HTML content
func extractTitle(html string) string {
	lowerHTML := strings.ToLower(html)

	// Find <title> tag
	titleStart := strings.Index(lowerHTML, "<title>")
	if titleStart == -1 {
		return ""
	}

	// Find </title> closing tag
	titleEnd := strings.Index(lowerHTML, "</title>")
	if titleEnd == -1 {
		return ""
	}

	// Extract title content
	titleStart += len("<title>")
	if titleEnd <= titleStart {
		return ""
	}

	return strings.TrimSpace(html[titleStart:titleEnd])
}

// extractDescription extracts meta description from HTML content
func extractDescription(html string) string {
	lowerHTML := strings.ToLower(html)

	// Find meta description tag
	descStart := strings.Index(lowerHTML, `<meta name="description"`)
	if descStart == -1 {
		// Try with single quotes
		descStart = strings.Index(lowerHTML, `<meta name='description'`)
	}
	if descStart == -1 {
		return ""
	}

	// Find content attribute
	contentStart := strings.Index(lowerHTML[descStart:], `content="`)
	if contentStart == -1 {
		// Try with single quotes
		contentStart = strings.Index(lowerHTML[descStart:], `content='`)
	}
	if contentStart == -1 {
