	descStart += contentStart + len(`content="`)

	// Find closing quote
	descEnd := strings.Index(lowerHTML[descStart:], `"`)
	if descEnd == -1 {
		// Try with single quotes
		descEnd = strings.Index(lowerHTML[descStart:], `'`)
	}
	if descEnd == -1 {
