// RequestPayload defines the expected structure of the incoming JSON request.
type RequestPayload struct {
	URL string `json:"url"`
}

// URLPreviewResponse defines the structure of the outgoing JSON response.
type URLPreviewResponse struct {
	Title       string `json:"title"`
	Description string `json:"description"`
	URL         string `json:"url"`
}

// Global regex patterns to avoid recompilation on every request.
var (
	titleRegex    = regexp.MustCompile(`(?i)<title[^>]*>(.*?)</title>`)
	metaTagRegex  = regexp.MustCompile(`(?i)<meta[^>]*>`)
	contentRegex  = regexp.MustCompile(`(?i)content=["']([^"']*)["']`)
)

// FetchURLPreview handles POST requests to fetch and parse metadata from a URL.
// It expects a JSON body with a "url" field and returns a JSON response containing the title and description.
func FetchURLPreview(ctx echo.Context) error {
	var req RequestPayload
	if err := ctx.Bind(&req); err != nil {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "Invalid request body: " + err.Error()})
	}

	if req.URL == "" {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "URL is required"})
	}

	// Create HTTP client with a 3-second timeout
	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	resp, err := client.Get(req.URL)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "Failed to fetch URL: " + err.Error()})
	}
	defer resp.Body.Close()

	// We only care about HTML content
	if resp.StatusCode != http.StatusOK {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "Received non-200 OK response status"})
	}

	// Limit body reading to 1MB to prevent memory exhaustion attacks
	bodyBytes, err := io.ReadAll(io.LimitReader(resp.Body, 1024*1024))
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "Failed to read response body"})
	}

	htmlContent := string(bodyBytes)
	title := extractTitle(htmlContent)
	description := extractDescription(htmlContent)

	return ctx.JSON(http.StatusOK, URLPreviewResponse{
		Title:       title,
		Description: description,
		URL:         req.URL,
	})
}

// extractTitle finds the content within the <title> tag.
func extractTitle(html string) string {
	matches := titleRegex.FindStringSubmatch(html)
	if len(matches) > 1 {
		return strings.TrimSpace(matches[1])
	}
	return ""
}

// extractDescription searches for a <meta name="description"> tag and extracts its content.
func extractDescription(html string) string {
	metaTags := metaTagRegex.FindAllString(html, -1)
	for _, tag := range metaTags {
		lowerTag := strings.ToLower(tag)
		// Check for name="description" or name='description'
		if strings.Contains(lowerTag, `name="description"`) || strings.Contains(lowerTag, `name='description'`) {
			contentMatch := contentRegex.FindStringSubmatch(tag)
			if len(contentMatch) > 1 {
				return strings.TrimSpace(contentMatch[1])
			}
		}
	}
	return ""
}

